const fs = require('fs');
const path = require('path');
const nunjucks = require('nunjucks');

const templatesDir = path.resolve(__dirname, '..', 'src', 'templates');
const outputDir = path.resolve(__dirname, '..', 'src', 'compiled-templates');
const oldOutputFile = path.resolve(__dirname, '..', 'src', 'compiled-templates.js');
const configureNunjucksEnv = require('../src/templates/nunjucks-env');

function collectTemplatesWrapper(templates) {
  return templates;
}

function templateModuleSource(template) {
  return `'use strict';

// This file is generated by ../../scripts/precompile-templates.js.
// Do not edit it manually.

module.exports = (function() {
${template}
})();
`;
}

function indexModuleSource(templates) {
  const entries = templates
    .map(({ name }) => `  ${JSON.stringify(name)}: require(${JSON.stringify('./' + name + '.js')})`)
    .join(',\n');

  return `'use strict';

// This file is generated by ../../scripts/precompile-templates.js.
// Do not edit it manually.

const nunjucks = require('nunjucks');
const configureNunjucksEnv = require('../templates/nunjucks-env');

const precompiledTemplates = {
${entries}
};

function normalizeTemplateName(name) {
  const normalized = [];
  const parts = name.replace(/\\\\/g, '/').split('/');

  parts.forEach((part) => {
    if (!part || part === '.') {
      return;
    }

    if (part === '..') {
      normalized.pop();
      return;
    }

    normalized.push(part);
  });

  return normalized.join('/');
}

function resolvePrecompiledTemplate(loader, parentName, filename) {
  if (!parentName || !loader.isRelative || !loader.isRelative(filename)) {
    return filename;
  }

  const parentParts = parentName.replace(/\\\\/g, '/').split('/');
  parentParts.pop();

  return normalizeTemplateName(parentParts.concat(filename).join('/'));
}

function createNunjucksEnv() {
  const loader = new nunjucks.PrecompiledLoader(precompiledTemplates);
  const env = new nunjucks.Environment(loader, { autoescape: false });

  env.resolveTemplate = resolvePrecompiledTemplate;
  configureNunjucksEnv(env);

  return env;
}

const nunjucksEnv = createNunjucksEnv();
const templates = Object.keys(precompiledTemplates).reduce((acc, name) => {
  acc[name] = nunjucksEnv.getTemplate(name);
  return acc;
}, {});

module.exports = {
  precompiledTemplates,
  templates,
  compiledTemplates: templates,
  nunjucksEnv,
  createNunjucksEnv
};
`;
}

function cleanOutput() {
  fs.rmSync(oldOutputFile, { force: true });
  fs.rmSync(outputDir, { recursive: true, force: true });
  fs.mkdirSync(outputDir, { recursive: true });
}

function main() {
  if (!fs.existsSync(templatesDir)) {
    throw new Error(`Templates directory does not exist: ${templatesDir}`);
  }

  const env = new nunjucks.Environment([], { autoescape: false });
  configureNunjucksEnv(env);

  const templates = nunjucks.precompile(templatesDir, {
    env,
    include: ['\\.njk$'],
    wrapper: collectTemplatesWrapper
  }).sort((a, b) => a.name.localeCompare(b.name));

  cleanOutput();

  templates.forEach(({ name, template }) => {
    fs.writeFileSync(path.join(outputDir, name + '.js'), templateModuleSource(template), 'utf8');
  });
  fs.writeFileSync(path.join(outputDir, 'index.js'), indexModuleSource(templates), 'utf8');

  console.log(`Generated ${templates.length} templates in ${path.relative(process.cwd(), outputDir)} from ${path.relative(process.cwd(), templatesDir)}.`);
}

try {
  main();
} catch (error) {
  console.error(error.message);
  process.exitCode = 1;
}
